array.string:
launchctl setenv XDG_CACHE_HOME "${HOME}/.dotfiles/cache";
launchctl setenv XDG_CONFIG_HOME "${HOME}/.dotfiles/config";
launchctl setenv XDG_DATA_HOME "${HOME}/.dotfiles/share";
launchctl setenv XDG_STATE_HOME "${HOME}/.dotfiles/state";
launchctl setenv XDG_LOCALS_DIR "${HOME}/.dotfiles/locals";
launchctl setenv XDG_SECURE_DIR "${HOME}/.dotfiles/secure";
launchctl setenv ZDOTDIR "${HOME}/.dotfiles/config/zsh";
launchctl setenv GNUPGHOME "${HOME}/Dropbox/gnupg";
